<div style="overflow: auto; width: 100%; height: 100%; background-color: #000000; color: #ffffff; padding: 10px 10px 0px 20px;">

{% set llm_cost_query = ' * GET llm_name, input_token_cost_per1M, output_token_cost_per1M' %}
{% set llm_costs = engine.query_stream_data(
    "llm_model_costs",
    cfxql_query=llm_cost_query,
    sorting=[{"llm_name": "asc"}],
    limit=100,
    max_rows=100
) %}
{% set costs = {} %}
{% for cost_row in llm_costs %}
    {% set _ = costs.update({
        cost_row.llm_name: [
            cost_row.input_token_cost_per1M | float, 
            cost_row.output_token_cost_per1M | float
        ]
    }) %}
{% endfor %}
{%- set cfxql_query2 = "conversationId = '"+ conversation_id + "' GET USER_ID,persona,message,conversationLabel,timestamp,type,llm,tool_name,token_usage_input_tokens,token_usage_cache_tokens,token_usage_output_tokens,tool_content,codeBlocks" -%}

{%- set convs = engine.query_stream_data("rda_chat_sessions", cfxql_query=cfxql_query2, sorting=[{"timestamp": "asc"}], limit=1000, max_rows=1000) -%}

{%- set ns = namespace(prompts=0, lasttime="", input=0, output=0, cache=0, cost=0, toolCount=0) -%}
{%- if convs -%}
    {%- set st = to_datetime(convs[0]["timestamp"]) -%}
    {%- set et = to_datetime(convs[-1]["timestamp"]) -%}

    {%- set convMap = {
        "USER_ID": convs[0]["USER_ID"],
        "persona": convs[0]["persona"],
        "conversationLabel": convs[0]["conversationLabel"],
        "duration": str((et-st).to_pytimedelta()).split(".")[0],
        "toolCount": 0,
        "prompts": 0,
        "cost": ""
      } -%}

    {%- for c in convs -%}
      {%- set ns.input = ns.input + c.get("token_usage_input_tokens",0) -%}
      {%- set ns.output = ns.output + c.get("token_usage_output_tokens",0) -%}
      {%- set ns.cache = ns.cache + c.get("token_usage_cache_tokens",0) -%}

      {# --- count tool calls --- #}
      {%- if c.get("tool_name") -%}
          {%- set ns.toolCount = ns.toolCount + 1 -%}
      {%- endif -%}

      {%- if costs.get(c.get("llm", "unknown")) -%}
          {%- set cm = costs.get(c.get("llm", ""), [0, 0]) -%}
          {%- set ns.cost = ns.cost + cm[0] *  c.get("token_usage_input_tokens",0)/1000000.0 + cm[1]*c.get("token_usage_output_tokens",0)/1000000.0 -%}
      {%- endif -%}
    {%- endfor -%}
    {%- set ns.cost = ns.cost | round(4) -%}

    <table width='90%' border=0 cellspacing=6 cellpadding=0>
    <tr>
        <td style='text-align: center; vertical-align: middle;'>
            <div style="display: inline-block; align-items: center;">
