                <span>User</span>
            </div>
        </td>

        <td style='text-align: center;  vertical-align: middle;'>
            <div style="display: inline-block; align-items: center;">
                <img src='/assets/img/icons/featureApp/svgIcons/collaboration.svg' style="width: 15px; height: auto; margin-right: 5px;">
                <span>Conversation Label</span>
            </div>
        </td>

        <td style='text-align: center;'>
            <div style="display: inline-block; align-items: center;">
                <img src='/assets/img/icons/featureApp/svgIcons/insights.svg' style="width: 15px; height: auto; margin-right: 5px;">
                <span>Persona</span>
            </div>
