            <div style='padding-left: 5px;'>{{convMap["conversationLabel"]}}</div>
        </td>
        <td style='text-align: center;  vertical-align: middle;font-size: 18px; font-weight: bold;'>
            <div style='padding-left: 5px;'>{{convMap["persona"]}}</div>
        </td>
        <td style='text-align: center;  vertical-align: middle; font-size: 18px; font-weight: bold;'>
            <div style='padding-left: 5px;'>{{convMap["duration"]}}</div>
        </td>
        <td style='text-align: center;  vertical-align: middle; font-size: 12px; font-weight: bold;'>
            <div style='padding-left: 5px; text-align: center; '>
                <center>
                <table border=0 cellspacing=5 cellpadding=1>
                  <tr>
                    <td style="text-align: center; border-bottom: 1px solid grey;">Input</td>
                    <td style="text-align: center; border-bottom: 1px solid grey;">Cache</td>
                    <td style="text-align: center; border-bottom: 1px solid grey;">Output</td>
                  </tr>
