              Output: {{ "{:,}".format(c.get("token_usage_output_tokens", 0)) }}, 
              Cache: {{ "{:,}".format(c.get("token_usage_cache_tokens", 0)) }}) </summary>
              <div style="overflow: auto; width: 90%; height: 200px; padding: 5px 5px 5px 5px; border-left: 1px solid #ff00ff;">
                {{c["message"]}}
              </div>
            </details>
          </div>
       {%- endif  -%}

    {%- endfor -%}

{%- else -%}
   <b>Conversation with ID {{conversation_id}} not found. May have been purged from the stream</b>
{%- endif -%}

</div>
