{%- set cfxql_query2 = "conversationId = '"+ conversation_id + "' GET USER_ID,persona,message,conversationLabel,timestamp,type,llm,tool_name,token_usage_input_tokens,token_usage_cache_tokens,token_usage_output_tokens,tool_content,codeBlocks" -%}
{%- set convs = engine.query_stream_data("rda_chat_sessions", cfxql_query=cfxql_query2, sorting=[{"timestamp": "asc"}], limit=1000, max_rows=1000) -%}

{%- set ns = namespace(prompts=0, lasttime="", input=0, output=0, cache=0, cost=0, toolCount=0) -%}
{%- if convs -%}
    {%- set st = to_datetime(convs[0]["timestamp"]) -%}
    {%- set et = to_datetime(convs[-1]["timestamp"]) -%}

    {%- set convMap = {
        "USER_ID": convs[0]["USER_ID"],
        "persona": convs[0]["persona"],
        "conversationLabel": convs[0]["conversationLabel"],
        "duration": str((et-st).to_pytimedelta()).split(".")[0],
        "toolCount": 0,
        "prompts": 0,
        "cost": ""
      } -%}

    {%- for c in convs -%}
      {%- set ns.input = ns.input + c.get("token_usage_input_tokens",0) -%}
      {%- set ns.output = ns.output + c.get("token_usage_output_tokens",0) -%}
      {%- set ns.cache = ns.cache + c.get("token_usage_cache_tokens",0) -%}

      {%- if c.get("tool_name") -%}
          {%- set ns.toolCount = ns.toolCount + 1 -%}
      {%- endif -%}

      {%- if costs.get(c.get("llm", "unknown")) -%}
          {%- set cm = costs.get(c.get("llm", ""), [0, 0]) -%}
          {%- set ns.cost = ns.cost + cm[0]*c.get("token_usage_input_tokens",0)/1000000.0 + cm[1]*c.get("token_usage_output_tokens",0)/1000000.0 -%}
      {%- endif -%}
    {%- endfor -%}
    {%- set ns.cost = ns.cost | round(4) -%}

    <table width='90%' border=0 cellspacing=6 cellpadding=0>
    <tr>
        <td style='text-align:center;'><img src='/assets/img/icons/featureApp/svgIcons/customer.svg' style="width:15px;"> User</td>
        <td style='text-align:center;'><img src='/assets/img/icons/featureApp/svgIcons/collaboration.svg' style="width:15px;"> Conversation Label</td>
        <td style='text-align:center;'><img src='/assets/img/icons/featureApp/svgIcons/insights.svg' style="width:15px;"> Persona</td>
        <td style='text-align:center;'><img src='/assets/img/icons/featureApp/svgIcons/schedule.svg' style="width:15px;"> Duration</td>
        <td style='text-align:center;'><img src='/assets/img/icons/featureApp/svgIcons/nextSteps.svg' style="width:15px;"> Tokens</td>
        <td style='text-align:center;'><img src='/assets/img/icons/featureApp/svgIcons/status.svg' style="width:15px;"> Estimated Cost</td>
        <td style='text-align:center;'><img src='/assets/img/icons/featureApp/svgIcons/remedial.svg' style="width:15px;"> Tools Called</td>
    </tr>
    <tr>
        <td style='text-align:center; font-size:18px; font-weight:bold;'>{{convMap["USER_ID"]}}</td>
        <td style='text-align:center; font-size:18px; font-weight:bold;'>{{convMap["conversationLabel"]}}</td>
        <td style='text-align:center; font-size:18px; font-weight:bold;'>{{convMap["persona"]}}</td>
        <td style='text-align:center; font-size:18px; font-weight:bold;'>{{convMap["duration"]}}</td>
        <td style='text-align:center; font-size:12px; font-weight:bold;'>
            <center>
            <table border=0 cellspacing=5 cellpadding=1>
              <tr>
                <td style="border-bottom:1px solid grey;">Input</td>
                <td style="border-bottom:1px solid grey;">Cache</td>
                <td style="border-bottom:1px solid grey;">Output</td>
              </tr>
              <tr>
                <td>{{"{:,}".format(ns.input)}}</td>
                <td>{{"{:,}".format(ns.cache)}}</td>
                <td>{{"{:,}".format(ns.output)}}</td>
              </tr>
            </table>
            </center>
        </td>
        <td style='text-align:center; font-size:18px; font-weight:bold;'>$ {{ns.cost}}</td>
        <td style='text-align:center; font-size:18px; font-weight:bold;'>{{ns.toolCount}}</td>
    </tr>
    </table>

    {%- for c in convs -%}
      <div style='height: 10px;'></div>
      {% if c["type"] == "client" %}
          <hr>
          {%- set ns.prompts = ns.prompts + 1 -%}
          <div style="display:flex; align-items:center; margin-top:5px; color:#888;">
            <img src='/assets/img/icons/featureApp/svgIcons/customer.svg' style="margin-right:5px; width:15px;"> 
            <span>{{c["timestamp"]}} <font color='#fff'>[<b>{{c["USER_ID"]}}</b>] {{c["message"]}}</font></span>
          </div>
          {%- set ns.lasttime = to_datetime(c["timestamp"]) -%}

      {% elif c["tool_name"] %}
          {%- set td = str((to_datetime(c["timestamp"])-ns.lasttime).to_pytimedelta()).split(".")[0] -%}
          {%- set ns.lasttime = to_datetime(c["timestamp"]) -%}
          <div style='padding-left:20px; color:#888;'>
            <details>
              <summary> + {{td}} <font color='#ffff00'>[<b>{{c["llm"]}}</b>] Tool Call: {{c["tool_name"]}}</font>
              (TOKENS Input: {{ "{:,}".format(c.get("token_usage_input_tokens", 0)) }},
              Output: {{ "{:,}".format(c.get("token_usage_output_tokens", 0)) }},
              Cache: {{ "{:,}".format(c.get("token_usage_cache_tokens", 0)) }}) </summary>
              <div style="overflow:auto; width:100%; height:500px; padding:5px; border-left:1px solid #ffff00;">
                {% set cb = c.get("codeBlocks", "") %}
                {% if cb %}
                  <pre>{{ cb | replace("\\n", "\n") | replace('\\"', '"') | replace("{", "") | replace("}", "") }}</pre>
                {% else %}
                  <pre><i style="color:#888;">No code blocks available for this tool call</i></pre>
                {% endif %}
              </div>
            </details>
          </div>

      {% else %}
          {%- set td = str((to_datetime(c["timestamp"])-ns.lasttime).to_pytimedelta()).split(".")[0] -%}
          {%- set ns.lasttime = to_datetime(c["timestamp"]) -%}
          <div style="display:flex; align-items:center; margin-top:5px; color:#888;">
            <img src='/assets/img/icons/featureApp/svgIcons/nlp.svg' style="margin-right:5px; width:15px;">
            <details>
              <summary>+ {{td}} <span style='color:#ff00ff;'>[<b>{{c["llm"]}}</b>] Response</span>
              (TOKENS Input: {{ "{:,}".format(c.get("token_usage_input_tokens", 0)) }},
              Output: {{ "{:,}".format(c.get("token_usage_output_tokens", 0)) }},
              Cache: {{ "{:,}".format(c.get("token_usage_cache_tokens", 0)) }})</summary>
              <div style="overflow:auto; width:90%; height:200px; padding:5px; border-left:1px solid #ff00ff;">
                {{c["message"]}}
              </div>
            </details>
          </div>
      {% endif %}
    {%- endfor -%}

{%- else -%}
   <b>Conversation with ID {{conversation_id}} not found. It may have been purged from the stream.</b>
{%- endif -%}

</div>
{% endraw %}

{% raw %}
<div style="overflow: auto; width: 100%; height: 100%; background-color: #000000; color: #ffffff; padding: 10px 10px 0px 20px;">

{% set llm_cost_query = ' * GET llm_name, input_token_cost_per1M, output_token_cost_per1M' %}
{% set llm_costs = engine.query_stream_data(
    "llm_model_costs",
    cfxql_query=llm_cost_query,
    sorting=[{"llm_name": "asc"}],
    limit=100,
    max_rows=100
) %}
{% set costs = {} %}
{% for cost_row in llm_costs %}
    {% set _ = costs.update({
        cost_row.llm_name: [
            cost_row.input_token_cost_per1M | float, 
            cost_row.output_token_cost_per1M | float
        ]
    }) %}
{% endfor %}

